-- ----------------------------------------------------------------------------
-- Loops: Table: Loops — the 10-loop build plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced and why.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS loops (
  loop_id                             TEXT                 PRIMARY KEY          -- Unique identifier: loop-01 through loop-10.
);
ALTER TABLE loops ADD COLUMN IF NOT EXISTS title TEXT;                                              -- Short title for what this loop adds to the domain model.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS status TEXT;                                             -- planned | in-progress | complete
ALTER TABLE loops ADD COLUMN IF NOT EXISTS new_concept TEXT;                                        -- The new first-class domain concept introduced this loop.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS domain_question TEXT;                                    -- The natural-language question this loop's concept answers FROM the domain data.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS mock_data_note TEXT;                                     -- What the seed data is designed to show.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS next_suggestion TEXT;                                    -- Suggestion for the next loop, written after witnessing the DAG at this loop's end.
COMMENT ON TABLE loops IS 'Table: Loops — the 10-loop build plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced and why.';
COMMENT ON COLUMN loops.loop_id IS 'Unique identifier: loop-01 through loop-10.';
COMMENT ON COLUMN loops.title IS 'Short title for what this loop adds to the domain model.';
COMMENT ON COLUMN loops.status IS 'planned | in-progress | complete';
COMMENT ON COLUMN loops.new_concept IS 'The new first-class domain concept introduced this loop.';
COMMENT ON COLUMN loops.domain_question IS 'The natural-language question this loop''s concept answers FROM the domain data.';
COMMENT ON COLUMN loops.mock_data_note IS 'What the seed data is designed to show.';
COMMENT ON COLUMN loops.next_suggestion IS 'Suggestion for the next loop, written after witnessing the DAG at this loop''s end.';

-- ----------------------------------------------------------------------------
-- Studies: Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS studies (
  study_id                            TEXT                 PRIMARY KEY          -- Unique slug for this study (e.g. kidney-1986, berkeley-1973).
);
ALTER TABLE studies ADD COLUMN IF NOT EXISTS title TEXT;                                            -- Human-readable title of the study.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS source TEXT;                                           -- Citation or description of the original data source.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS source_url TEXT;                                       -- URL to the original source.
COMMENT ON TABLE studies IS 'Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.';
COMMENT ON COLUMN studies.study_id IS 'Unique slug for this study (e.g. kidney-1986, berkeley-1973).';
COMMENT ON COLUMN studies.title IS 'Human-readable title of the study.';
COMMENT ON COLUMN studies.source IS 'Citation or description of the original data source.';
COMMENT ON COLUMN studies.source_url IS 'URL to the original source.';

-- ----------------------------------------------------------------------------
-- Treatments: Table: Treatments — the interventions being compared within a study. Each treatment belongs to one study.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS treatments (
  treatment_id                        TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-A, kidney-1986-B).
);
ALTER TABLE treatments ADD COLUMN IF NOT EXISTS study TEXT;                                         -- FK to the parent Study.
ALTER TABLE treatments ADD COLUMN IF NOT EXISTS treatment_label TEXT;                               -- Short label used in CaseCells and comparisons (e.g. A, B).
ALTER TABLE treatments ADD COLUMN IF NOT EXISTS description TEXT;                                   -- Plain-language description of what this treatment is.
COMMENT ON TABLE treatments IS 'Table: Treatments — the interventions being compared within a study. Each treatment belongs to one study.';
COMMENT ON COLUMN treatments.treatment_id IS 'Unique slug (e.g. kidney-1986-A, kidney-1986-B).';
COMMENT ON COLUMN treatments.study IS 'FK to the parent Study.';
COMMENT ON COLUMN treatments.treatment_label IS 'Short label used in CaseCells and comparisons (e.g. A, B).';
COMMENT ON COLUMN treatments.description IS 'Plain-language description of what this treatment is.';

-- ----------------------------------------------------------------------------
-- Strata: Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS strata (
  stratum_id                          TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-small, kidney-1986-large).
);
ALTER TABLE strata ADD COLUMN IF NOT EXISTS study TEXT;                                             -- FK to the parent Study.
ALTER TABLE strata ADD COLUMN IF NOT EXISTS stratum_label TEXT;                                     -- Short label used in CaseCells (e.g. small, large, dept-A).
ALTER TABLE strata ADD COLUMN IF NOT EXISTS description TEXT;                                       -- Plain-language description of what defines this stratum.
COMMENT ON TABLE strata IS 'Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.';
COMMENT ON COLUMN strata.stratum_id IS 'Unique slug (e.g. kidney-1986-small, kidney-1986-large).';
COMMENT ON COLUMN strata.study IS 'FK to the parent Study.';
COMMENT ON COLUMN strata.stratum_label IS 'Short label used in CaseCells (e.g. small, large, dept-A).';
COMMENT ON COLUMN strata.description IS 'Plain-language description of what defines this stratum.';

-- ----------------------------------------------------------------------------
-- CaseCells: Table: CaseCells — the raw leaves of the DAG. One row per (study, stratum, treatment) combination recording the aggregate count of successes and total cases. Every derived fact in the model traces back to these numbers. Nothing above this row is a raw input.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS case_cells (
  case_cell_id                        TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-small-A).
);
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS study TEXT;                                         -- FK to the parent Study.
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS stratum_label TEXT;                                 -- The stratum this cell belongs to (matches Strata.StratumLabel).
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS treatment_label TEXT;                               -- The treatment applied in this cell (matches Treatments.TreatmentLabel).
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS successes INTEGER;                                  -- Number of patients in this cell who had a successful outcome. RAW INPUT — never derived.
ALTER TABLE case_cells ADD COLUMN IF NOT EXISTS cases INTEGER;                                      -- Total number of patients in this cell. RAW INPUT — never derived.
COMMENT ON TABLE case_cells IS 'Table: CaseCells — the raw leaves of the DAG. One row per (study, stratum, treatment) combination recording the aggregate count of successes and total cases. Every derived fact in the model traces back to these numbers. Nothing above this row is a raw input.';
COMMENT ON COLUMN case_cells.case_cell_id IS 'Unique slug (e.g. kidney-1986-small-A).';
COMMENT ON COLUMN case_cells.study IS 'FK to the parent Study.';
COMMENT ON COLUMN case_cells.stratum_label IS 'The stratum this cell belongs to (matches Strata.StratumLabel).';
COMMENT ON COLUMN case_cells.treatment_label IS 'The treatment applied in this cell (matches Treatments.TreatmentLabel).';
COMMENT ON COLUMN case_cells.successes IS 'Number of patients in this cell who had a successful outcome. RAW INPUT — never derived.';
COMMENT ON COLUMN case_cells.cases IS 'Total number of patients in this cell. RAW INPUT — never derived.';

